use actix_web::{web, App, HttpResponse, HttpRequest, Responder};
use diesel::prelude::*;
use diesel::SqliteConnection;
use std::env;

table! {
    invoices (id) {
        id -> Integer,
        user_id -> Integer,
        amount -> Float,
    }
}

impl From<SqliteConnection> for Connection<SqliteConnection> {
    fn from(connection: SqliteConnection) -> Self {
        Connection::new(connection)
    }
}

let db = sqlx::connect("sqlite:///invoices.db");

async fn get_invoice(req: HttpRequest, pool: web::Data<Pool<SqlConnection>>) -> impl Responder {
    let id = req.match_info().get("id").unwrap_or("0") .parse::<i32>().expect("Invalid invoice ID");
    let conn = pool.get().await.expect("Unable to acquire connection");

    use super::*;

    let result = diesel::query(invoices::table.find(id).load)(conn)
        .expect("Error executing query");

    match result.len() {
        0 => HttpResponse::NotFound().finish(),
        _ => format!("ID: {} \nUser ID: {}\nAmount: {}", id, result[0].user_id, result[0].amount).into(),
    }
}

fn main() {
    let mut config = actix_web::AppConfig::default();

    config.data(db.unwrap());
    config.route("/invoices/{id}", web::get().to(get_invoice));

    actix_web::server::new_service(config)
        .workers(2)
        .bind("127.0.0.1:8080")?
        .run()?;
}